-- RaftersIQ — Denver Christian Girls Soccer bulk load (auto-generated from MaxPreps PDFs)
-- Run in Supabase SQL editor. Idempotent: wipes & reloads THIS program only.
-- NOTE: 2024-25 PLAYER stats excluded (sparse source format) — re-import that season via the app.
do $$
declare pid uuid;
begin
  select id into pid from public.programs where slug='denver-christian-soccer-girls';
  if pid is null then raise exception 'Girls Soccer program not found'; end if;
  delete from public.player_seasons where program_id=pid;
  delete from public.all_time_players where program_id=pid;
  delete from public.athletes where program_id=pid;
  delete from public.seasons where program_id=pid;
  on conflict (program_id, lower(player_name), season) do update set stats=excluded.stats;
  raise notice 'DC Girls Soccer loaded';
end $$;
NOTIFY pgrst, 'reload schema';